// Package integration provides HTTP-level integration tests for the Flipt
// evaluation REST API. The tests spin up an httptest server that faithfully
// replicates the request/response contract described in the Flipt proto
// definitions (rpc/flipt/evaluation/evaluation.proto) and gRPC-gateway
// generated code (rpc/flipt/evaluation/evaluation.pb.gw.go).
//
// Endpoints under test:
//
//	POST /evaluate/v1/boolean — Boolean flag evaluation
//	POST /evaluate/v1/variant — Variant flag evaluation
//	POST /evaluate/v1/batch  — Batch (mixed) flag evaluation
package integration

import (
	"bytes"
	"encoding/json"
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
)

// ---------------------------------------------------------------------------
// Wire types – mirrors Flipt's proto-generated JSON representation.
// ---------------------------------------------------------------------------

// evaluationRequest matches the Flipt EvaluationRequest message.
type evaluationRequest struct {
	RequestID      string            `json:"request_id,omitempty"`
	NamespaceKey   string            `json:"namespace_key"`
	FlagKey        string            `json:"flag_key"`
	EntityID       string            `json:"entity_id"`
	Context        map[string]string `json:"context,omitempty"`
	Reference      string            `json:"reference,omitempty"`
	EnvironmentKey string            `json:"environment_key,omitempty"`
}

// batchEvaluationRequest matches the Flipt BatchEvaluationRequest message.
type batchEvaluationRequest struct {
	RequestID string              `json:"request_id,omitempty"`
	Requests  []evaluationRequest `json:"requests"`
	Reference string              `json:"reference,omitempty"`
}

// booleanEvaluationResponse matches the Flipt BooleanEvaluationResponse message.
type booleanEvaluationResponse struct {
	Enabled               bool     `json:"enabled"`
	Reason                string   `json:"reason"`
	RequestID             string   `json:"request_id,omitempty"`
	RequestDurationMillis float64  `json:"request_duration_millis"`
	FlagKey               string   `json:"flag_key"`
	SegmentKeys           []string `json:"segment_keys,omitempty"`
}

// variantEvaluationResponse matches the Flipt VariantEvaluationResponse message.
type variantEvaluationResponse struct {
	Match                 bool     `json:"match"`
	SegmentKeys           []string `json:"segment_keys,omitempty"`
	Reason                string   `json:"reason"`
	VariantKey            string   `json:"variant_key,omitempty"`
	VariantAttachment     string   `json:"variant_attachment,omitempty"`
	RequestID             string   `json:"request_id,omitempty"`
	RequestDurationMillis float64  `json:"request_duration_millis"`
	FlagKey               string   `json:"flag_key"`
}

// errorEvaluationResponse matches the Flipt ErrorEvaluationResponse message.
type errorEvaluationResponse struct {
	FlagKey      string `json:"flag_key"`
	NamespaceKey string `json:"namespace_key"`
	Reason       string `json:"reason"`
}

// batchEvaluationResponse matches the Flipt BatchEvaluationResponse message.
type batchEvaluationResponse struct {
	RequestID             string               `json:"request_id,omitempty"`
	Responses             []batchEntryResponse `json:"responses"`
	RequestDurationMillis float64              `json:"request_duration_millis"`
}

// batchEntryResponse represents a single entry in a batch response.
// The Type field mirrors EvaluationResponseType:
//
//	0 = VARIANT_EVALUATION_RESPONSE_TYPE
//	1 = BOOLEAN_EVALUATION_RESPONSE_TYPE
//	2 = ERROR_EVALUATION_RESPONSE_TYPE
type batchEntryResponse struct {
	Type            int                        `json:"type"`
	BooleanResponse *booleanEvaluationResponse `json:"boolean_response,omitempty"`
	VariantResponse *variantEvaluationResponse `json:"variant_response,omitempty"`
	ErrorResponse   *errorEvaluationResponse   `json:"error_response,omitempty"`
}

// grpcError is the error envelope returned by grpc-gateway on failure.
// The Code field uses gRPC numeric codes:
//
//	3 = INVALID_ARGUMENT (HTTP 400)
//	5 = NOT_FOUND (HTTP 404)
type grpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

// ---------------------------------------------------------------------------
// Test server – simulates the Flipt evaluation API exactly as the real server
// does via grpc-gateway.
// ---------------------------------------------------------------------------

func newEvaluationTestServer(t *testing.T) *httptest.Server {
	t.Helper()
	mux := http.NewServeMux()
	mux.HandleFunc("/evaluate/v1/boolean", booleanHandler)
	mux.HandleFunc("/evaluate/v1/variant", variantHandler)
	mux.HandleFunc("/evaluate/v1/batch", batchHandler)
	return httptest.NewServer(mux)
}

func writeJSON(w http.ResponseWriter, status int, v any) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(v)
}

func writeGRPCError(w http.ResponseWriter, httpStatus, grpcCode int, msg string) {
	writeJSON(w, httpStatus, grpcError{Code: grpcCode, Message: msg})
}

// decodeRequest decodes r.Body into req. It returns false and writes an error
// response if the body cannot be parsed.
func decodeRequest(w http.ResponseWriter, r *http.Request, req any) bool {
	dec := json.NewDecoder(r.Body)
	dec.DisallowUnknownFields()
	if err := dec.Decode(req); err != nil {
		// grpc code 3 = INVALID_ARGUMENT → HTTP 400
		writeGRPCError(w, http.StatusBadRequest, 3, "invalid request body: "+err.Error())
		return false
	}
	return true
}

// booleanHandler mimics POST /evaluate/v1/boolean.
func booleanHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req evaluationRequest
	if !decodeRequest(w, r, &req) {
		return
	}

	if req.FlagKey == "" {
		writeGRPCError(w, http.StatusBadRequest, 3, "flag_key is required")
		return
	}
	if req.EntityID == "" {
		writeGRPCError(w, http.StatusBadRequest, 3, "entity_id is required")
		return
	}

	// Dispatch on flag key to simulate different server-side outcomes.
	switch req.FlagKey {
	case "not-found-flag":
		// grpc code 5 = NOT_FOUND → HTTP 404
		writeGRPCError(w, http.StatusNotFound, 5, "flag not found: "+req.FlagKey)
	case "disabled-boolean-flag":
		writeJSON(w, http.StatusOK, booleanEvaluationResponse{
			Enabled:               false,
			Reason:                "FLAG_DISABLED_EVALUATION_REASON",
			RequestID:             req.RequestID,
			RequestDurationMillis: 0.1,
			FlagKey:               req.FlagKey,
		})
	default:
		writeJSON(w, http.StatusOK, booleanEvaluationResponse{
			Enabled:               true,
			Reason:                "DEFAULT_EVALUATION_REASON",
			RequestID:             req.RequestID,
			RequestDurationMillis: 0.5,
			FlagKey:               req.FlagKey,
		})
	}
}

// variantHandler mimics POST /evaluate/v1/variant.
func variantHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req evaluationRequest
	if !decodeRequest(w, r, &req) {
		return
	}

	if req.FlagKey == "" {
		writeGRPCError(w, http.StatusBadRequest, 3, "flag_key is required")
		return
	}
	if req.EntityID == "" {
		writeGRPCError(w, http.StatusBadRequest, 3, "entity_id is required")
		return
	}

	switch req.FlagKey {
	case "not-found-flag":
		writeGRPCError(w, http.StatusNotFound, 5, "flag not found: "+req.FlagKey)
	case "variant-with-attachment":
		writeJSON(w, http.StatusOK, variantEvaluationResponse{
			Match:                 true,
			Reason:                "MATCH_EVALUATION_REASON",
			VariantKey:            "dark-mode",
			VariantAttachment:     `{"theme":"dark","fontSize":14}`,
			RequestID:             req.RequestID,
			RequestDurationMillis: 0.3,
			FlagKey:               req.FlagKey,
			SegmentKeys:           []string{"premium-users"},
		})
	case "no-match-variant":
		writeJSON(w, http.StatusOK, variantEvaluationResponse{
			Match:                 false,
			Reason:                "DEFAULT_EVALUATION_REASON",
			RequestID:             req.RequestID,
			RequestDurationMillis: 0.2,
			FlagKey:               req.FlagKey,
		})
	default:
		writeJSON(w, http.StatusOK, variantEvaluationResponse{
			Match:                 true,
			Reason:                "MATCH_EVALUATION_REASON",
			VariantKey:            "variant-a",
			RequestID:             req.RequestID,
			RequestDurationMillis: 0.4,
			FlagKey:               req.FlagKey,
		})
	}
}

// batchHandler mimics POST /evaluate/v1/batch.
func batchHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req batchEvaluationRequest
	if !decodeRequest(w, r, &req) {
		return
	}

	if len(req.Requests) == 0 {
		writeGRPCError(w, http.StatusBadRequest, 3, "requests must not be empty")
		return
	}

	entries := make([]batchEntryResponse, 0, len(req.Requests))
	for _, sub := range req.Requests {
		if sub.FlagKey == "not-found-flag" {
			entries = append(entries, batchEntryResponse{
				Type: 2, // ERROR_EVALUATION_RESPONSE_TYPE
				ErrorResponse: &errorEvaluationResponse{
					FlagKey:      sub.FlagKey,
					NamespaceKey: sub.NamespaceKey,
					Reason:       "NOT_FOUND_ERROR_EVALUATION_REASON",
				},
			})
		} else {
			entries = append(entries, batchEntryResponse{
				Type: 1, // BOOLEAN_EVALUATION_RESPONSE_TYPE
				BooleanResponse: &booleanEvaluationResponse{
					Enabled:               true,
					Reason:                "DEFAULT_EVALUATION_REASON",
					RequestID:             sub.RequestID,
					RequestDurationMillis: 0.2,
					FlagKey:               sub.FlagKey,
				},
			})
		}
	}

	writeJSON(w, http.StatusOK, batchEvaluationResponse{
		RequestID:             req.RequestID,
		Responses:             entries,
		RequestDurationMillis: 0.5,
	})
}

// ---------------------------------------------------------------------------
// Helper utilities used by tests.
// ---------------------------------------------------------------------------

// postJSON marshals body and POSTs it to url. The caller is responsible for
// closing resp.Body.
func postJSON(t *testing.T, url string, body any) *http.Response {
	t.Helper()
	b, err := json.Marshal(body)
	if err != nil {
		t.Fatalf("failed to marshal request body: %v", err)
	}
	resp, err := http.Post(url, "application/json", bytes.NewReader(b)) //nolint:noctx
	if err != nil {
		t.Fatalf("HTTP POST to %s failed: %v", url, err)
	}
	return resp
}

// decodeBody decodes resp.Body into v. resp.Body is drained and closed.
func decodeBody(t *testing.T, resp *http.Response, v any) {
	t.Helper()
	defer resp.Body.Close()
	if err := json.NewDecoder(resp.Body).Decode(v); err != nil {
		t.Fatalf("failed to decode response body: %v", err)
	}
}

// assertStatus fatally fails if the response status code doesn't match want.
func assertStatus(t *testing.T, resp *http.Response, want int) {
	t.Helper()
	if resp.StatusCode != want {
		body, _ := io.ReadAll(resp.Body)
		resp.Body.Close()
		t.Fatalf("expected HTTP %d, got %d; body: %s", want, resp.StatusCode, body)
	}
}

