// TestBooleanEvaluation_Success verifies that a valid boolean flag evaluation
// request returns HTTP 200 with the expected response fields populated.
func TestBooleanEvaluation_Success(t *testing.T) {
	srv := newEvaluationTestServer(t)
	defer srv.Close()

	req := evaluationRequest{
		RequestID:      "req-001",
		NamespaceKey:   "default",
		FlagKey:        "checkout-v2",
		EntityID:       "user-abc",
		Context:        map[string]string{"plan": "pro", "region": "us-east"},
		EnvironmentKey: "production",
	}

	resp := postJSON(t, srv.URL+"/evaluate/v1/boolean", req)
	assertStatus(t, resp, http.StatusOK)

	var result booleanEvaluationResponse
	decodeBody(t, resp, &result)

	if result.FlagKey != req.FlagKey {
		t.Errorf("flag_key: got %q, want %q", result.FlagKey, req.FlagKey)
	}
	if !result.Enabled {
		t.Error("enabled: got false, want true")
	}
	if result.Reason == "" {
		t.Error("reason must not be empty")
	}
	if result.RequestID != req.RequestID {
		t.Errorf("request_id: got %q, want %q", result.RequestID, req.RequestID)
	}
}

// TestBooleanEvaluation_DisabledFlag checks that a disabled flag returns
