// TestVariantEvaluation_Success verifies a successful variant flag evaluation
// returning a matched variant key and JSON attachment.
func TestVariantEvaluation_Success(t *testing.T) {
	srv := newEvaluationTestServer(t)
	defer srv.Close()

	req := evaluationRequest{
		RequestID:      "req-variant-001",
		NamespaceKey:   "default",
		FlagKey:        "variant-with-attachment",
		EntityID:       "user-premium-001",
		Context:        map[string]string{"plan": "premium"},
		EnvironmentKey: "production",
	}

	resp := postJSON(t, srv.URL+"/evaluate/v1/variant", req)
	assertStatus(t, resp, http.StatusOK)

	var result variantEvaluationResponse
	decodeBody(t, resp, &result)

	if !result.Match {
		t.Error("match: got false, want true")
	}
	if result.VariantKey != "dark-mode" {
		t.Errorf("variant_key: got %q, want %q", result.VariantKey, "dark-mode")
	}
	if result.VariantAttachment == "" {
		t.Error("variant_attachment must not be empty")
	}
	// Verify the attachment is valid JSON.
	var attachment map[string]any
	if err := json.Unmarshal([]byte(result.VariantAttachment), &attachment); err != nil {
		t.Errorf("variant_attachment is not valid JSON: %v", err)
	}
	if result.FlagKey != req.FlagKey {
		t.Errorf("flag_key: got %q, want %q", result.FlagKey, req.FlagKey)
	}
	if len(result.SegmentKeys) == 0 {
		t.Error("segment_keys must not be empty when match is true")
	}
