// TestEvaluation_NamespaceScoping verifies that requests carrying different
// namespace keys are accepted and the flag_key in the response reflects the
// original request's flag key (not a cross-namespace leak).
func TestEvaluation_NamespaceScoping(t *testing.T) {
	srv := newEvaluationTestServer(t)
	defer srv.Close()

	tests := []struct {
		namespace string
		flagKey   string
		entityID  string
	}{
