// TestEvaluation_InvalidRequestBody verifies that malformed JSON bodies are
// rejected with HTTP 400 and gRPC INVALID_ARGUMENT code (3).
func TestEvaluation_InvalidRequestBody(t *testing.T) {
	srv := newEvaluationTestServer(t)
	defer srv.Close()

	malformedBodies := []struct {
		name string
		body string
	}{
		{"empty_body", ``},
		{"not_json", `this is not json`},
		{"unclosed_brace", `{"flag_key": "foo"`},
	}

	endpoints := []string{"/evaluate/v1/boolean", "/evaluate/v1/variant", "/evaluate/v1/batch"}

	for _, ep := range endpoints {
		for _, tc := range malformedBodies {
			t.Run(strings.TrimPrefix(ep, "/evaluate/v1/")+"/"+tc.name, func(t *testing.T) {
				resp, err := http.Post(srv.URL+ep, "application/json", strings.NewReader(tc.body))
				if err != nil {
					t.Fatalf("HTTP POST failed: %v", err)
				}
				if resp.StatusCode != http.StatusBadRequest {
					body, _ := io.ReadAll(resp.Body)
					resp.Body.Close()
					t.Fatalf("expected HTTP 400, got %d; body: %s", resp.StatusCode, body)
				}

				var errBody grpcError
				decodeBody(t, resp, &errBody)

				if errBody.Code != 3 {
					t.Errorf("grpc error code: got %d, want 3 (INVALID_ARGUMENT)", errBody.Code)
				}
				if errBody.Message == "" {
					t.Error("error message must not be empty")
				}
			})
		}
	}
}

// TestBatchEvaluation_Success verifies that a batch request containing
// multiple flags (all found) returns HTTP 200 with a response entry per
// request, all indicating success.
func TestBatchEvaluation_Success(t *testing.T) {
	srv := newEvaluationTestServer(t)
	defer srv.Close()

	req := batchEvaluationRequest{
		RequestID: "batch-req-001",
		Requests: []evaluationRequest{
			{
				FlagKey:      "flag-alpha",
				NamespaceKey: "default",
				EntityID:     "user-1",
				Context:      map[string]string{"env": "prod"},
			},
			{
				FlagKey:      "flag-beta",
				NamespaceKey: "default",
				EntityID:     "user-1",
				Context:      map[string]string{"env": "prod"},
			},
		},
	}

	resp := postJSON(t, srv.URL+"/evaluate/v1/batch", req)
	assertStatus(t, resp, http.StatusOK)

	var result batchEvaluationResponse
	decodeBody(t, resp, &result)

	if len(result.Responses) != len(req.Requests) {
		t.Fatalf("responses count: got %d, want %d", len(result.Responses), len(req.Requests))
	}
	for i, entry := range result.Responses {
		if entry.ErrorResponse != nil {
			t.Errorf("response[%d]: unexpected error response: %+v", i, entry.ErrorResponse)
		}
		if entry.BooleanResponse == nil {
			t.Errorf("response[%d]: expected boolean_response, got nil", i)
			continue
		}
		if entry.BooleanResponse.FlagKey != req.Requests[i].FlagKey {
			t.Errorf("response[%d] flag_key: got %q, want %q",
				i, entry.BooleanResponse.FlagKey, req.Requests[i].FlagKey)
		}
	}
	if result.RequestDurationMillis <= 0 {
		t.Error("request_duration_millis must be positive")
	}
}

// TestBatchEvaluation_MixedResults verifies the batch endpoint's behaviour
// when some flags exist and some do not: missing flags yield an
// ErrorEvaluationResponse entry with NOT_FOUND_ERROR_EVALUATION_REASON
// rather than causing the entire batch to fail.
func TestBatchEvaluation_MixedResults(t *testing.T) {
	srv := newEvaluationTestServer(t)
	defer srv.Close()

	req := batchEvaluationRequest{
		RequestID: "batch-mixed-001",
		Requests: []evaluationRequest{
			{
				FlagKey:      "existing-flag",
				NamespaceKey: "default",
				EntityID:     "user-42",
				Context:      map[string]string{},
			},
			{
				FlagKey:      "not-found-flag",
				NamespaceKey: "default",
				EntityID:     "user-42",
				Context:      map[string]string{},
			},
		},
	}

	resp := postJSON(t, srv.URL+"/evaluate/v1/batch", req)
	assertStatus(t, resp, http.StatusOK)

	var result batchEvaluationResponse
	decodeBody(t, resp, &result)

	if len(result.Responses) != 2 {
		t.Fatalf("responses count: got %d, want 2", len(result.Responses))
	}

	// First entry should succeed.
	first := result.Responses[0]
	if first.ErrorResponse != nil {
		t.Errorf("response[0]: unexpected error: %+v", first.ErrorResponse)
	}
	if first.BooleanResponse == nil {
		t.Error("response[0]: expected boolean_response")
	}

	// Second entry should carry an error for the missing flag.
	second := result.Responses[1]
	if second.ErrorResponse == nil {
		t.Fatal("response[1]: expected error_response for missing flag, got nil")
	}
	if second.ErrorResponse.FlagKey != "not-found-flag" {
		t.Errorf("response[1] error flag_key: got %q, want %q",
			second.ErrorResponse.FlagKey, "not-found-flag")
	}
	if second.ErrorResponse.Reason != "NOT_FOUND_ERROR_EVALUATION_REASON" {
		t.Errorf("response[1] error reason: got %q, want NOT_FOUND_ERROR_EVALUATION_REASON",
			second.ErrorResponse.Reason)
	}
}

